export const getMyStoriesService = async (userId) => {
    if (!userId) {
        throw { status: 400, error: 'userId is required' };
    }

    const { data, error } = await supabase
        .from('stories')
        .select(`*, chapters(id, chapter_number, title, status, word_count)`)
        .eq('author_id', userId)
        .order('updated_at', { ascending: false });

    if (error) {
        console.error('supabase error fetching my stories:', error.message);
        throw { status: 500, error: 'failed to fetch stories' };
    }

    return (data || []).map(stripEmbedding);
};

